export function getOrRefresh<T>(
  key: string,
  ttl: number,
  refreshFn: () => Promise<T>
): Promise<T> {
  const entry = cache.get(key);
  const now = Date.now();

  // Check and set atomically within this call
  if (entry && now < entry.expiry) {
    return Promise.resolve(entry.value as T);
  }

  // Refresh needed - use mutex to prevent stampede
  return refreshWithLock(key, ttl, refreshFn);
}

// Implement lock per key to prevent thundering herd
const locks = new Map<string, Promise<any>>();
function refreshWithLock<T>(
  key: string,
  ttl: number,
  refreshFn: () => Promise<T>
): Promise<T> {
  const existing = locks.get(key);
  if (existing) return existing as Promise<T>;

  const promise = refreshFn().then(value => {
    cache.set(key, { value, expiry: Date.now() + ttl });
    locks.delete(key);
    return value;
  });
  locks.set(key, promise);
  return promise;
}
```

